1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty array for empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells that each have only one neighbor (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a cell alive that has exactly 2 live neighbors (survival)", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
16	    expect(result).toContainEqual([1, 0]);
17	  });
18	  it.todo("should keep a cell alive that has exactly 3 live neighbors (survival)");
19	  it.todo("should kill a cell that has 4 or more live neighbors (overpopulation)");
20	  it.todo("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)");
21	  it.todo("should keep a block pattern unchanged (still life)");
22	  it.todo("should oscillate a blinker pattern (oscillator)");
23	});
24

1	type Cell = [number, number];
2	
3	const isNeighbor = (cell: Cell, other: Cell): boolean =>
4	  !(other[0] === cell[0] && other[1] === cell[1]) &&
5	  Math.abs(other[0] - cell[0]) <= 1 &&
6	  Math.abs(other[1] - cell[1]) <= 1;
7	
8	const countNeighbors = (cell: Cell, liveCells: Cell[]): number =>
9	  liveCells.filter((other) => isNeighbor(cell, other)).length;
10	
11	export function nextGeneration(liveCells: Cell[]): Cell[] {
12	  return liveCells.filter((cell) => countNeighbors(cell, liveCells) === 2);
13	}
